//  Sequential (Slow: Takes 2 seconds total)
async function loadDashboardSlow() {
  // Waits 1s
  const profile = await fetch('/api/profile').then(r => r.json()); 
  // Waits another 1s
  const settings = await fetch('/api/settings').then(r => r.json());
  render(profile, settings);
}

//  Parallel (Fast: Takes 1 second total)
async function loadDashboardFast() {
  // Both network requests are fired off immediately
  const profilePromise = fetch('/api/profile').then(r => r.json());
  const settingsPromise = fetch('/api/settings').then(r => r.json());

  // Await them both at the same time
  const [profile, settings] = await Promise.all([profilePromise, settingsPromise]);
  render(profile, settings);
}

