// Sequential loop (Slow)
for (const id of [1, 2, 3]) {
  await fetch(`/api/user/${id}`); // 1 finishes, then 2 starts...
}

// Parallel loop (Fast)
const promises = [1, 2, 3].map(id => fetch(`/api/user/${id}`));
await Promise.all(promises); // All 3 start at the same time
